    taskid: 2dd8909a-834d-4e71-87d0-180b8ab44860
    type: condition
    task:
      id: 2dd8909a-834d-4e71-87d0-180b8ab44860
      version: -1
      name: If in the night
      description: Decide if the event is late in the night. If it is report this
        as an intruder Critical alert.
      type: condition
      iscommand: false
      brand: ""
    nexttasks:
      '#default#':
      - "10"
      "yes":
      - "6"
    separatecontext: false
    conditions:
    - label: "yes"
      condition:
      - - operator: greaterThanOrEqual
          left:
            value:
              complex:
                root: incident
                accessor: occurred
                transformers:
                - operator: Cut
                  args:
                    delimiter:
                      value:
                        simple: T
                    fields:
                      value:
                        simple: "2"
                - operator: Cut
                  args:
                    delimiter:
                      value:
                        simple: ':'
                    fields:
                      value:
                        simple: "1"
                - operator: abs
            iscontext: true
          right:
            value:
              simple: inputs.NightHourStart
            iscontext: true
        - operator: lessThanOrEqual
          left:
            value:
              complex:
                root: incident
                accessor: occurred
                transformers:
                - operator: Cut
                  args:
                    delimiter:
                      value:
                        simple: T
                    fields:
                      value:
                        simple: "2"
                - operator: Cut
                  args:
                    delimiter:
                      value:
                        simple: ':'
                    fields:
                      value:
                        simple: "1"
                - operator: abs
            iscontext: true
          right:
            value:
              simple: inputs.NightHourEnd
            iscontext: true
    view: |-
      {
        "position": {
          "x": 700,
          "y": 900
        }
      }
    note: false
    timertriggers: []
    ignoreworker: false
    skipunavailable: false
    quietmode: 0
